145→        private async Task<IReadOnlyDictionary<string, ServiceTreeNode>> QueryHierarchyBatchAsync(
146→            IReadOnlyList<string> batch,
147→            CancellationToken cancellationToken)
148→        {
149→            var results = new Dictionary<string, ServiceTreeNode>(StringComparer.OrdinalIgnoreCase);
150→            if (batch.Count == 0)
151→            {
152→                return results;
153→            }
154→
155→            // Build a fast-lookup set of the (already-lowercased) input IDs so we can
156→            // cross-key results by whichever hierarchy column matched each row.
157→            var batchSet = new HashSet<string>(
158→                batch.Select(id => id.ToLowerInvariant()),
159→                StringComparer.OrdinalIgnoreCase);
160→
161→            var hierarchyTable = this.NormalizeIdentifier(this.kustoOptions.HierarchyTableName);
162→            var builder = new StringBuilder();
163→            builder.AppendLine("let ids = datatable(TargetId:string)[");
164→            builder.Append(string.Join(", ", batch.Select(id => $"'{EscapeKustoString(id.ToLowerInvariant())}'")));
165→            builder.AppendLine("];");
166→            builder.AppendLine($"{hierarchyTable}");
167→            builder.AppendLine("| where tolower(ServiceId) in (ids)");
168→            builder.AppendLine("    or tolower(column_ifexists(\"TeamGroupId\", \"\")) in (ids)");
169→            builder.AppendLine("    or tolower(column_ifexists(\"ServiceGroupId\", \"\")) in (ids)");
170→            builder.AppendLine("    or tolower(column_ifexists(\"OrganizationId\", \"\")) in (ids)");
171→            builder.AppendLine("    or tolower(column_ifexists(\"DivisionId\", \"\")) in (ids)");
172→            builder.AppendLine("| project");
173→            builder.AppendLine("    Id = tostring(ServiceId),");
174→            builder.AppendLine("    Name = tostring(column_ifexists(\"ServiceName\", \"\")),");
175→            builder.AppendLine("    Level = tostring(column_ifexists(\"ServiceLevel\", \"\")),");
176→            builder.AppendLine("    TeamGroupId = tostring(column_ifexists(\"TeamGroupId\", \"\")),");
177→            builder.AppendLine("    TeamGroupName = tostring(column_ifexists(\"TeamGroupName\", \"\")),");
178→            builder.AppendLine("    ServiceGroupId = tostring(column_ifexists(\"ServiceGroupId\", \"\")),");
179→            builder.AppendLine("    ServiceGroupName = tostring(column_ifexists(\"ServiceGroupName\", \"\")),");
180→            builder.AppendLine("    OrganizationId = tostring(column_ifexists(\"OrganizationId\", \"\")),");
181→            builder.AppendLine("    OrganizationName = tostring(column_ifexists(\"OrganizationName\", \"\")),");
182→            builder.AppendLine("    DivisionId = tostring(column_ifexists(\"DivisionId\", \"\")),");
183→            builder.AppendLine("    DivisionName = tostring(column_ifexists(\"DivisionName\", \"\"))");
184→            var query = builder.ToString();
185→
186→            var requestProperties = new ClientRequestProperties();
187→            requestProperties.ClientRequestId = $"CodexSite.ServiceTreeHierarchy.{Guid.NewGuid():N}";
188→
189→            try
190→            {
191→                this.logger.LogInformation(
192→                    "ServiceTreeKustoClient: Executing hierarchy query for {BatchCount} IDs against {Cluster}/{Database}/{Table}.",
193→                    batch.Count,
194→                    this.kustoOptions.ClusterUri,
195→                    this.kustoOptions.Database,
196→                    this.kustoOptions.HierarchyTableName);
197→
198→                using var provider = this.CreateQueryProvider();
199→                using var reader = await provider.ExecuteQueryAsync(this.kustoOptions.Database, query, requestProperties);
200→
201→                do
202→                {
203→                    var idOrdinal = this.TryGetOrdinal(reader, "Id");
204→                    if (idOrdinal < 0)
205→                    {
206→                        continue;
207→                    }
208→
209→                    var nameOrdinal = this.TryGetOrdinal(reader, "Name");
210→                    var levelOrdinal = this.TryGetOrdinal(reader, "Level");
211→                    var teamGroupIdOrdinal = this.TryGetOrdinal(reader, "TeamGroupId");
212→                    var serviceGroupIdOrdinal = this.TryGetOrdinal(reader, "ServiceGroupId");
213→                    var serviceGroupNameOrdinal = this.TryGetOrdinal(reader, "ServiceGroupName");
214→                    var organizationIdOrdinal = this.TryGetOrdinal(reader, "OrganizationId");
215→                    var organizationNameOrdinal = this.TryGetOrdinal(reader, "OrganizationName");
216→                    var divisionIdOrdinal = this.TryGetOrdinal(reader, "DivisionId");
217→                    var divisionNameOrdinal = this.TryGetOrdinal(reader, "DivisionName");
218→
219→                    while (reader.Read())
220→                    {
221→                        var id = this.ReadString(reader, idOrdinal);
222→                        if (string.IsNullOrWhiteSpace(id))
223→                        {
224→                            continue;
225→                        }
226→
227→                        var node = new ServiceTreeNode
228→                        {
229→                            Id = id,
230→                            Name = this.ReadString(reader, nameOrdinal),
231→                            Level = this.ReadString(reader, levelOrdinal),
232→                            ServiceGroupId = this.ReadString(reader, serviceGroupIdOrdinal),
233→                            ServiceGroupName = this.ReadString(reader, serviceGroupNameOrdinal),
234→                            OrganizationId = this.ReadString(reader, organizationIdOrdinal),
235→                            OrganizationName = this.ReadString(reader, organizationNameOrdinal),
236→                            DivisionId = this.ReadString(reader, divisionIdOrdinal),
237→                            DivisionName = this.ReadString(reader, divisionNameOrdinal),
238→                        };
239→
240→                        // Always key by the native ServiceId for backward compatibility.
241→                        results[id] = node;
