243→                        // Also key by any hierarchy ancestor ID that the caller asked for.
244→                        // This lets a caller who passed an OrganizationId (or ServiceGroupId etc.)
245→                        // find the result via hierarchyResults.TryGetValue(inputId).
246→                        var teamGroupId = this.ReadString(reader, teamGroupIdOrdinal);
247→                        foreach (var hierarchyId in new[]
248→                        {
249→                            teamGroupId,
250→                            node.ServiceGroupId,
251→                            node.OrganizationId,
252→                            node.DivisionId,
253→                        })
254→                        {
